[CmdletBinding()]
param([Parameter(Mandatory)][string]$Title,[Parameter(Mandatory)][string]$Target,[string]$Root=(Get-Location).Path,[switch]$Json)
$ErrorActionPreference='Stop';$dir=Join-Path $Root '.ueef\refactor-recipes';New-Item -ItemType Directory -Path $dir -Force|Out-Null;$id=([regex]::Replace($Title.ToLower(),'[^a-z0-9]+','-')).Trim('-');$path=Join-Path $dir "$id.md";if(Test-Path $path){throw "Recipe already exists: $path"};$text="# Refactor Recipe: $Title`n`nTarget: $Target`nStatus: DRAFT`n`n## Characterization baseline`n- [ ] Record current behavior and focused tests.`n`n## Safe steps`n- [ ] Make one reversible change.`n- [ ] Run focused tests after each step.`n`n## Acceptance`n- [ ] Behavior remains compatible or migration is documented.`n`n## Rollback`n- [ ] Revert the isolated commit or restore the recorded baseline.`n`nExecution is manual; this recipe does not modify source code.";Set-Content $path $text -Encoding utf8;$r=[ordered]@{schemaVersion=1;path=$path;automaticExecution=$false;requiresBaseline=$true;requiresRollback=$true};if($Json){$r|ConvertTo-Json}else{Write-Output "Refactor recipe created: $path"}
